    ["oilplant-mk03"] = {"py-oil-powerplant-mk03", "oil-molten-salt-03", "he-03"},
    ["biomassplant-mk04"] = {"py-biomass-powerplant-mk04", "biomass-molten-salt-04", "he-04"},
    ["coalplant-mk04"] = {"py-coal-powerplant-mk04", "coal-molten-salt-04", "he-04"},
    ["gasplant-mk04"] = {"py-gas-powerplant-mk04", "gas-molten-salt-04", "he-04"},
    ["oilplant-mk04"] = {"py-oil-powerplant-mk04", "oil-molten-salt-04", "he-04"},
    -- TODO: Reorder unlocks for remaining py3 technologies and beyond
}

if (settings.startup["pysimple-descriptions"].value and not mods["PyBlock"]) or technology_adjustments ~= "1" then
    if not (settings.startup["py-tank-adjust"].value or settings.startup["pysimple-storage-tanks"].value) then tech_unlocks["py-storage-tanks"] = nil end
    -- reorders recipe unlocks by priority based on the above table
    for tech,unlocks in pairs(tech_unlocks) do
        if data.raw.technology[tech] then
            local use_index = true
            for i,unlock in pairs(unlocks) do
                if use_index then
                    local added = add_unlock(unlock, tech, tech, i)
                    if not added then use_index = false end -- prevents issues due to missing recipes such as those related to "decay" which results in tables of different sizes
                else
                    add_unlock(unlock, tech, tech)
                end
            end
        end
    end
end
